                is_missing=True; token='EMPTY/NaN'
            else:
                s=str(v).strip()
                if s=='':
                    is_missing=True; token='EMPTY_STRING'
                elif s.lower() in {'n/a','na','tbd','???','null','none','nan'}:
                    is_missing=True; token=s
                elif re.fullmatch(r'\?{3,}',s):
                    is_missing=True; token=s
