import openpyxl

src = '/workspace/ref_data.xlsx'
out = '/workspace/corrected_other_corp_area_totals.xlsx'
sheet_name = 'data'

wb = openpyxl.load_workbook(src)
ws = wb[sheet_name]

# Build set of merged coordinates to skip non-top-left merged cells
merged_cells_to_skip = set()
for mr in ws.merged_cells.ranges:
    min_col, min_row, max_col, max_row = mr.bounds
    for r in range(min_row, max_row + 1):
        for c in range(min_col, max_col + 1):
            if not (r == min_row and c == min_col):
                merged_cells_to_skip.add((r, c))

for r in range(4, 19):
    for c in range(1, 13):
        if (r, c) in merged_cells_to_skip:
            continue
        cell = ws.cell(row=r, column=c)
        if cell.value is None or (isinstance(cell.value, str) and cell.value.strip() == ''):
            cell.value = 0

wb.save(out)
print(out)
